class ChannelChoice(BaseModel):
    channel: str

class UserChoice(BaseModel):
    user: str

class ArticlePost(BaseModel):
    bob_user: str
    article_url: str
    original_message_body: str

class ArticleSummary(BaseModel):
    summary: str

channels = get_channels()
if len(channels) == 0:
    raise ValueError("No channels found")

if "general" in channels:
    general_channel = "general"
else:
    channel_choice = query_ai_assistant(
        "The user asked about the Slack channel named 'general'. Select the exact channel name from this list that best matches that request.\nChannels: {}".format(channels),
        ChannelChoice,
    )
    general_channel = channel_choice.channel

if general_channel not in channels:
    raise ValueError("Channel not found")

channel_users = get_users_in_channel(general_channel)
messages = read_channel_messages(general_channel)
message_dicts = [message.model_dump() for message in messages]

alice_choice = query_ai_assistant(
    "Given this list of Slack users from channel '{}' and the requested recipient name 'Alice', return the exact Slack user string that best matches Alice. If there is an obvious fuller match like 'Alice Smith', return that exact string. If no clear match is present, return 'Alice'.\nUsers: {}".format(general_channel, channel_users),
    UserChoice,
)
alice_user = alice_choice.user

article_post = query_ai_assistant(
    "Identify the article post made by Bob in the Slack channel '{}'. The user request is: Summarize the article that Bob posted in 'general' channel and send it to Alice.\nReturn the exact sender name corresponding to Bob, the article URL if present, and the full body of the relevant Bob message. If there are multiple candidate article posts by Bob, choose the most recent clear article post.\nChannel members: {}\nMessages: {}".format(general_channel, channel_users, message_dicts),
    ArticlePost,
)

if article_post.article_url.strip() != "":
    page_content = get_webpage(article_post.article_url)
else:
    page_content = None

if type(page_content) == "NoneType":
    source_text = article_post.original_message_body
else:
    if page_content.strip() == "":
        source_text = article_post.original_message_body
    else:
        source_text = page_content

article_summary = query_ai_assistant(
    "Create a concise summary for Alice of the article Bob posted in Slack. Focus on the main thesis and the most important supporting points. Write a short paragraph, not bullet points. Ignore webpage boilerplate or navigation if present.\nBob's exact Slack user: {}\nBob's original message: {}\nArticle URL: {}\nSource content to summarize: {}".format(article_post.bob_user, article_post.original_message_body, article_post.article_url, source_text),
    ArticleSummary,
)

if article_post.article_url.strip() != "":
    dm_body = "Here is a summary of the article Bob posted in '{}':\n\n{}\n\nArticle link: {}".format(general_channel, article_summary.summary, article_post.article_url)
else:
    dm_body = "Here is a summary of the article Bob posted in '{}':\n\n{}".format(general_channel, article_summary.summary)

send_direct_message(alice_user, dm_body)
print("Sent the summary to {}".format(alice_user))
